const bubbles = $('Fetch Bubbles').first().json.bubbles || [];
const store = $getWorkflowStaticData('global');
if (!store.notified) store.notified = {};  // { bubbleId: 'YYYY-MM-DD' }

const nowMs = Date.now();
const H24 = 24 * 3600 * 1000;
const today = new Date().toISOString().slice(0, 10);

// Build parent index for context (so we can show 'Goal / Subtask')
const byId = {};
for (const b of bubbles) byId[b.id] = b;
function parentTitle(b) {
  if (!b.parent_id) return null;
  const p = byId[b.parent_id];
  return p ? p.title : null;
}

const burning = [];
for (const b of bubbles) {
  if (b.status !== 'active') continue;
  if (!b.deadline) continue;
  const dlMs = typeof b.deadline === 'number' ? b.deadline : Date.parse(b.deadline);
  if (!dlMs || isNaN(dlMs)) continue;
  const diffMs = dlMs - nowMs;
  // Burning if deadline is within +/- 24h window (24h before — горит, just-passed — просрочено)
  if (diffMs > H24) continue;
  if (diffMs < -H24) continue;
  if (store.notified[b.id] === today) continue;
  burning.push({
    id: b.id,
    title: b.title,
    parent: parentTitle(b),
    type: b.type,
    deadline: dlMs,
    diffH: Math.round(diffMs / 3600000),
    overdue: diffMs < 0
  });
}

// Mark notified (will be persisted in static data after workflow run)
for (const b of burning) store.notified[b.id] = today;

// Cleanup old notified entries (>30 days)
const cutoff = new Date(Date.now() - 30 * 24 * 3600 * 1000).toISOString().slice(0, 10);
for (const id of Object.keys(store.notified)) {
  if (store.notified[id] < cutoff) delete store.notified[id];
}

if (!burning.length) return [{ json: { hasBurning: false, total: bubbles.length, syncedTotal: bubbles.length } }];

// Format TG message
const lines = ['🔥 Горящие задачи (' + burning.length + ')', ''];
for (const b of burning) {
  const path = b.parent ? (b.parent + ' / ' + b.title) : b.title;
  const time = b.overdue
    ? '⛔ просрочено на ' + Math.abs(b.diffH) + 'ч'
    : '⏳ через ' + b.diffH + 'ч';
  lines.push('· ' + path + '  —  ' + time);
}

return [{ json: { hasBurning: true, text: lines.join('\n'), burning, total: bubbles.length, syncedTotal: bubbles.length } }];
